    (425, '(Dialogo) A: "Pitääkö minun ottaa taksi lentokentälle?" / B: "Kyllä, se on paras ratkaisu."', 'phrase', 'f0c6563c979c621b06266b2cbe8b6209be82b800ad3ef07bcf07247331d90fef', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_143", "note_culturale": "Dare un consiglio. ''È la cosa migliore'' / ''se on paras ratkaisu'' (è la soluzione migliore) / ''that''s your best bet'' (idioma)."}', NULL),
    (426, '(Dialogo) A: "Should I take a taxi to the airport?" / B: "Yes, that''s your best bet."', 'phrase', '4673583d27a1d40d51bbe7ce842e5411448040b8a9d078a621f794849cdf629b', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_143", "note_culturale": "Dare un consiglio. ''È la cosa migliore'' / ''se on paras ratkaisu'' (è la soluzione migliore) / ''that''s your best bet'' (idioma)."}', NULL),
    (427, '(Dialogo) A: "A che ora è la colazione in hotel?" / B: "Dalle 7 alle 10."', 'phrase', '82b081e7241f0bb873a5638bfb224d75d4fcb9f3bcbc7fe40a0772817ba88fbf', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_144", "note_culturale": "Richiesta di informazioni standard in hotel."}', NULL),
    (428, '(Dialogo) A: "Mihin aikaan aamiainen on hotellissa?" / B: "Seitsemästä kymmeneen."', 'phrase', '215b4cc80dc93e3ea8ca17fc99967b4b8af6875c99b15c9f3852905427cbd5db', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_144", "note_culturale": "Richiesta di informazioni standard in hotel."}', NULL),
    (429, '(Dialogo) A: "What time is breakfast at the hotel?" / B: "From 7 to 10."', 'phrase', '9f1117cc126593afce3e361ad7c0ee8823e8fda43612c1321299b7bd5f949542', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_144", "note_culturale": "Richiesta di informazioni standard in hotel."}', NULL),
    (430, '(Dialogo) A: "Scusi, è questo l''autobus per il centro?" / B: "No, deve prendere il 10."', 'phrase', '3120f15ac3aa8c93b928790f6ac586c8fea73b430290a1731469e0cfdb8a5e3b', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_145", "note_culturale": "Chiedere e correggere indicazioni per i trasporti pubblici."}', NULL),
    (431, '(Dialogo) A: "Anteeksi, meneekö tämä bussi keskustaan?" / B: "Ei, teidän täytyy ottaa numero 10."', 'phrase', '9bc39b97817da4d4dcb2a12aad9765bd5a7db8b27dd16ce211d2d0f724754903', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_145", "note_culturale": "Chiedere e correggere indicazioni per i trasporti pubblici."}', NULL),
    (432, '(Dialogo) A: "Excuse me, is this the bus to the city center?" / B: "No, you need to take the number 10."', 'phrase', 'cbe446f188c15cda193f8cc47efad2ff5470dc26b9b139b97e8c7cbb21fc2699', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_145", "note_culturale": "Chiedere e correggere indicazioni per i trasporti pubblici."}', NULL),
    (433, '(Dialogo) A: "Hai la carta d''imbarco?" / B: "Sì, è qui sul telefono."', 'phrase', '749f2d4794f3c277c139047d55ff4dc49b785afe43de967fd40b09bf339ddf21', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_146", "note_culturale": "Dialogo standard in aeroporto."}', NULL),
    (434, '(Dialogo) A: "Onko sinulla tarkastuskortti?" / B: "Kyllä, se on tässä puhelimessa."', 'phrase', '589b7ee7bc0768475edcf7f4b46c9d45e33064dce11953139ed3169658e75ac4', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_146", "note_culturale": "Dialogo standard in aeroporto."}', NULL),
    (435, '(Dialogo) A: "Do you have the boarding pass?" / B: "Yes, it''s here on my phone."', 'phrase', 'b2c83aef92e9832d1333179c1db920db534934bafe0cb20f70fa66ec39e360c4', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_146", "note_culturale": "Dialogo standard in aeroporto."}', NULL),
    (436, '(Dialogo) A: "Hai finito il report?" / B: "Non ancora, ci sto lavorando."', 'phrase', 'f41ef3ec1cfefe9b23bbb43386d3a31799fcc81bd0b9964146ee1c5cf9aa57f0', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_147", "note_culturale": "Dialogo B1 standard in ufficio. ''Ci sto lavorando'' / ''työstän sitä parhaillaan'' (lo sto lavorando proprio ora) / ''I''m working on it''."}', NULL),
    (437, '(Dialogo) A: "Saitko raportin valmiiksi?" / B: "En vielä, työstän sitä parhaillaan."', 'phrase', '0f54697f77980b1a98af0282766dc2c62674349384cdb48b3a0831d8a461cf1f', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_147", "note_culturale": "Dialogo B1 standard in ufficio. ''Ci sto lavorando'' / ''työstän sitä parhaillaan'' (lo sto lavorando proprio ora) / ''I''m working on it''."}', NULL),
    (438, '(Dialogo) A: "Did you finish the report?" / B: "Not yet, I''m working on it."', 'phrase', 'b46ae9e5811b24fe46d865a2b6b8e6392ed131fba9556282193b4ed639c2a80a', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_147", "note_culturale": "Dialogo B1 standard in ufficio. ''Ci sto lavorando'' / ''työstän sitä parhaillaan'' (lo sto lavorando proprio ora) / ''I''m working on it''."}', NULL),
    (439, '(Dialogo) A: "Il capo sembra nervoso oggi." / B: "Sì, meglio stargli alla larga."', 'phrase', '20a638e888b01d4e63c8a755a4639ec10c8ccdc30029bcfdf396dc97128e9b82', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_148", "note_culturale": "Consiglio colloquiale in ufficio. ''Stare alla larga'' (IT) e ''steer clear of'' (EN) sono idiomi equivalenti. Il finlandese è più letterale."}', NULL),
    (440, '(Dialogo) A: "Pomo vaikuttaa hermostuneelta tänään." / B: "Joo, on parasta pysyä kaukana hänestä."', 'phrase', '5d91731b014e59866bd8c46f1abc6298500a4805102407d60ffb69ebf4d722e0', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_148", "note_culturale": "Consiglio colloquiale in ufficio. ''Stare alla larga'' (IT) e ''steer clear of'' (EN) sono idiomi equivalenti. Il finlandese è più letterale."}', NULL),
    (441, '(Dialogo) A: "The boss seems nervous today." / B: "Yeah, it''s best to steer clear of him."', 'phrase', '1e352a690e0f7a67e5d415f834cca2f53f619b43ac0e5a9b71cb7c9092327655', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_148", "note_culturale": "Consiglio colloquiale in ufficio. ''Stare alla larga'' (IT) e ''steer clear of'' (EN) sono idiomi equivalenti. Il finlandese è più letterale."}', NULL),
