    (443, '(Dialogo) A: "Miten kokous meni?" / B: "Hyvin, pääsimme asian ytimeen."', 'phrase', '596a95198dbad8cb5a72c2ad6931b9bae9e85ff2029c4b0d7246c788ec3ebf94', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_149", "note_culturale": "Idiomi per ''arrivare al punto centrale''. ''Nocciolo della questione'' (IT), ''asian ydin'' (FI, nucleo della questione), ''crux of the matter'' (EN)."}', NULL),
    (444, '(Dialogo) A: "How did the meeting go?" / B: "Good, we got to the crux of the matter."', 'phrase', '4bdffd86a63301a037cd9abdd6877beaa6b49c7d16ec2fdda255eccd9f570806', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_149", "note_culturale": "Idiomi per ''arrivare al punto centrale''. ''Nocciolo della questione'' (IT), ''asian ydin'' (FI, nucleo della questione), ''crux of the matter'' (EN)."}', NULL),
    (445, '(Dialogo) A: "Dobbiamo finire questo entro venerdì." / B: "Lo so, siamo messi male con i tempi."', 'phrase', 'bb1492f74e1d3d8ed59c074fe7ebaf727301da2ad1c2826ae2e092651864aa63', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_150", "note_culturale": "Idiomi per ''avere poco tempo''. ''Siamo messi male con i tempi'' (IT), ''tiukka aikataulu'' (FI, calendario stretto), ''tight schedule'' (EN)."}', NULL),
    (446, '(Dialogo) A: "Tämän on oltava valmis perjantaihin mennessä." / B: "Tiedän, meillä on tiukka aikataulu."', 'phrase', '0180cbd6022f95d419ad845ddf95e8ab7750249ccaffa1f92741b36e0abed5f0', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_150", "note_culturale": "Idiomi per ''avere poco tempo''. ''Siamo messi male con i tempi'' (IT), ''tiukka aikataulu'' (FI, calendario stretto), ''tight schedule'' (EN)."}', NULL),
    (447, '(Dialogo) A: "We have to finish this by Friday." / B: "I know, we''re on a tight schedule."', 'phrase', '1291569311c598b1556b996a5daab0c4c91b9ba4af2ad6263c7f02b93736dcdc', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_150", "note_culturale": "Idiomi per ''avere poco tempo''. ''Siamo messi male con i tempi'' (IT), ''tiukka aikataulu'' (FI, calendario stretto), ''tight schedule'' (EN)."}', NULL),
    (448, '(Dialogo) A: "Hai chiesto l''aumento?" / B: "Non ancora, aspetto il momento giusto."', 'phrase', '8a2f0a8b1d5179a0c5bfa5ba25bef430c2133cee0871966e613b896b585d12e4', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_151", "note_culturale": "Parlare di tempismo per una decisione importante. ''Momento giusto'' / ''oikea hetki'' / ''right moment''."}', NULL),
    (449, '(Dialogo) A: "Pyysitkö palkankorotusta?" / B: "En vielä, odotan oikeaa hetkeä."', 'phrase', '5a034c8488cfb1e50f5d16524c299eeeb84cc6b114645c86cb6c230df73e023f', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_151", "note_culturale": "Parlare di tempismo per una decisione importante. ''Momento giusto'' / ''oikea hetki'' / ''right moment''."}', NULL),
    (450, '(Dialogo) A: "Did you ask for a raise?" / B: "Not yet, I''m waiting for the right moment."', 'phrase', 'bd2e9d4d5c9f27be8c9ef00b4f33caef1cfff020b1b8d943ff1f1b0fa16f91d3', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_151", "note_culturale": "Parlare di tempismo per una decisione importante. ''Momento giusto'' / ''oikea hetki'' / ''right moment''."}', NULL),
    (451, '(Dialogo) A: "Perché sei così stanco?" / B: "Sono sommerso di lavoro."', 'phrase', '9aeeb23089ff9047566beebeb94b3dd57ddc3ab0067bd756c4e942a4dfbf188d', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_152", "note_culturale": "Idiomi per ''avere troppo lavoro''. ''Essere sommerso'' (IT), ''hukkua töihin'' (FI, affogare nel lavoro), ''to be swamped'' (EN, essere impaludato)."}', NULL),
    (452, '(Dialogo) A: "Miksi olet niin väsynyt?" / B: "Hukun töihin."', 'phrase', 'b5cc5f13747cc431582e94282c63f28589a6b6e14675ef9061b501f634deabc4', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_152", "note_culturale": "Idiomi per ''avere troppo lavoro''. ''Essere sommerso'' (IT), ''hukkua töihin'' (FI, affogare nel lavoro), ''to be swamped'' (EN, essere impaludato)."}', NULL),
    (453, '(Dialogo) A: "Why are you so tired?" / B: "I''m swamped with work."', 'phrase', '6827d85af492da6a644d547d16e7cc43374026ad5cdc0c3ad80bae2a32beeefe', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_152", "note_culturale": "Idiomi per ''avere troppo lavoro''. ''Essere sommerso'' (IT), ''hukkua töihin'' (FI, affogare nel lavoro), ''to be swamped'' (EN, essere impaludato)."}', NULL),
    (454, '(Dialogo) A: "Hai parlato con Luca?" / B: "Sì, lo tengo d''occhio. Non mi fido."', 'phrase', '59ecd6c69ba4c104a0dd5079fa032b40269814cbd3be23d98e0a0e182e2026b6', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_153", "note_culturale": "Idiomi per ''sorvegliare''. Tutte e tre le lingue usano la metafora dell''occhio: ''tenere d''occhio'' / ''pitää silmällä'' / ''keeping an eye on''."}', NULL),
    (455, '(Dialogo) A: "Puitko Lucan kanssa?" / B: "Joo, pidän häntä silmällä. En luota häneen."', 'phrase', '8b6c38b8e5fb032e57fe55c42c0dea52f1eaa7a059e8212973798e7287d938f2', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_153", "note_culturale": "Idiomi per ''sorvegliare''. Tutte e tre le lingue usano la metafora dell''occhio: ''tenere d''occhio'' / ''pitää silmällä'' / ''keeping an eye on''."}', NULL),
    (456, '(Dialogo) A: "Did you talk to Luca?" / B: "Yes, I''m keeping an eye on him. I don''t trust him."', 'phrase', '92fa441ad4cad40334523531812652e29d87cc1350cf1fe809e645d6ea97bf92', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_153", "note_culturale": "Idiomi per ''sorvegliare''. Tutte e tre le lingue usano la metafora dell''occhio: ''tenere d''occhio'' / ''pitää silmällä'' / ''keeping an eye on''."}', NULL),
    (457, '(Dialogo) A: "Cosa pensi della nuova collega?" / B: "Non saprei, non riesco a inquadrarla."', 'phrase', '32d1d17a706b630de7e3efba5eb3583ca0d857513613f8c46cce76d54b5f40d2', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_154", "note_culturale": "Idiomi per ''non riuscire a capire una persona''. ''Inquadrare'' (IT), ''päästä perille'' (FI, arrivare [alla sua natura]), ''figure out'' (EN)."}', NULL),
    (458, '(Dialogo) A: "Mitä mieltä olet uudesta kollegasta?" / B: "En osaa sanoa, en pääse hänestä perille."', 'phrase', '2e713bb202157990b971fe81e5b3c647d4ad4ac7120d7a2f50099c1422016564', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_154", "note_culturale": "Idiomi per ''non riuscire a capire una persona''. ''Inquadrare'' (IT), ''päästä perille'' (FI, arrivare [alla sua natura]), ''figure out'' (EN)."}', NULL),
    (459, '(Dialogo) A: "What do you think of the new colleague?" / B: "I don''t know, I can''t quite figure her out."', 'phrase', '9f31291e5309a360eff59f52f6650e1fa1d14d9ff9ae090a6930601bcc5e9421', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_154", "note_culturale": "Idiomi per ''non riuscire a capire una persona''. ''Inquadrare'' (IT), ''päästä perille'' (FI, arrivare [alla sua natura]), ''figure out'' (EN)."}', NULL),
    (460, '(Dialogo) A: "Oggi non combino niente." / B: "Sì, è una giornata no."', 'phrase', '8b48ceb6516795d8fac3ccd5da4669bb94bd1ad15411f9aca5ebabdc55bc34d9', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_155", "note_culturale": "Esprimere improduttività. ''Giornata no'' (IT) / ''huono päivä'' (FI, giornata cattiva) / ''one of those days'' (EN, idiom)."}', NULL),
    (461, '(Dialogo) A: "En saa tänään mitään aikaiseksi." / B: "Joo, tämä on huono päivä."', 'phrase', 'a77bfc63febd8b28beb7b409965cb7c319a1188118b519970720d5ec4cd5dce1', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_155", "note_culturale": "Esprimere improduttività. ''Giornata no'' (IT) / ''huono päivä'' (FI, giornata cattiva) / ''one of those days'' (EN, idiom)."}', NULL),
    (462, '(Dialogo) A: "I''m not getting anything done today." / B: "Yeah, it''s just one of those days."', 'phrase', '77e2be1c4cdef6aecd0444c08be0a07f24b14dbd8f903a14ad4f4aa26a28a200', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_155", "note_culturale": "Esprimere improduttività. ''Giornata no'' (IT) / ''huono päivä'' (FI, giornata cattiva) / ''one of those days'' (EN, idiom)."}', NULL),
    (463, '(Dialogo) A: "Hai sentito la notizia?" / B: "Sì, gira voce che chiuderanno il reparto."', 'phrase', '6d554a59901d8d4e695a0c7f940054e6629366c1bb848f6e453723ee55aa257c', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_156", "note_culturale": "Idiomi per ''si dice''. ''Gira voce'' (IT) / ''huhu kiertää'' (FI, la voce circola) / ''rumor has it'' (EN)."}', NULL),
    (464, '(Dialogo) A: "Kuulitko uutiset?" / B: "Kyllä, huhu kiertää, että osasto suljetaan."', 'phrase', 'd50759437e7a6b043fef65b9f528e4c4217aa0be8673065c0459213ccd31a71b', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_156", "note_culturale": "Idiomi per ''si dice''. ''Gira voce'' (IT) / ''huhu kiertää'' (FI, la voce circola) / ''rumor has it'' (EN)."}', NULL),
    (465, '(Dialogo) A: "Did you hear the news?" / B: "Yes, rumor has it they''re closing the department."', 'phrase', '439fa29cc2db500b766d7a14d5189125b7700add55fbc4a8313d93750f1826a6', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_156", "note_culturale": "Idiomi per ''si dice''. ''Gira voce'' (IT) / ''huhu kiertää'' (FI, la voce circola) / ''rumor has it'' (EN)."}', NULL),
    (466, '(Dialogo) A: "Hai mandato l''email?" / B: "Me n''ero completamente dimenticato! Lo faccio subito."', 'phrase', '824c73bd6e164dcd5608ef22713405e2501c7f403da0c7bec20ce017b180c9ed', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_157", "note_culturale": "Idiomi per ''dimenticarsi''. ''Me n''ero dimenticato'' (IT), ''olin unohtanut'' (FI), ''it slipped my mind'' (EN, mi è scivolato dalla mente)."}', NULL),
    (467, '(Dialogo) A: "Lähetitkö sen sähköpostin?" / B: "Olin unohtanut sen täysin! Teen sen heti."', 'phrase', '70fe01587b6c5252e71db6c4b32e497c3b366f00fd82a5a8098fa104c490b64a', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_157", "note_culturale": "Idiomi per ''dimenticarsi''. ''Me n''ero dimenticato'' (IT), ''olin unohtanut'' (FI), ''it slipped my mind'' (EN, mi è scivolato dalla mente)."}', NULL),
    (468, '(Dialogo) A: "Did you send the email?" / B: "It totally slipped my mind! I''ll do it right now."', 'phrase', '7a5ce8388856ed47c1f72fb7dba920b0d092c3172cfcc364a6036cf976eba3d8', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_157", "note_culturale": "Idiomi per ''dimenticarsi''. ''Me n''ero dimenticato'' (IT), ''olin unohtanut'' (FI), ''it slipped my mind'' (EN, mi è scivolato dalla mente)."}', NULL),
    (469, '(Dialogo) A: "Il cliente ha accettato!" / B: "Perfetto! Domani chiudiamo l''accordo."', 'phrase', '5daf2facfad04e2671aae305c80a491c3bd5ed1d48296f382aed1d4ff7be09cf', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_158", "note_culturale": "Idiomi per ''finalizzare un contratto''. ''Chiudere l''accordo'' (IT), ''tehdä kaupat'' (FI, fare gli affari), ''close the deal'' (EN)."}', NULL),
    (470, '(Dialogo) A: "Asiakas hyväksyi!" / B: "Hienoa! Tehdään kaupat huomenna."', 'phrase', 'a58ba631f16e18413d8b18e1ce86bef9229ca8e3da36c10b860f8e9f664ff466', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_158", "note_culturale": "Idiomi per ''finalizzare un contratto''. ''Chiudere l''accordo'' (IT), ''tehdä kaupat'' (FI, fare gli affari), ''close the deal'' (EN)."}', NULL),
    (471, '(Dialogo) A: "The client accepted!" / B: "Perfect! We''ll close the deal tomorrow."', 'phrase', '392747608c63ce72d668082a1dedff5afab38876cddbf6d047af0db341f09d8b', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_158", "note_culturale": "Idiomi per ''finalizzare un contratto''. ''Chiudere l''accordo'' (IT), ''tehdä kaupat'' (FI, fare gli affari), ''close the deal'' (EN)."}', NULL),
    (472, '(Dialogo) A: "Sei sicuro che sia una buona idea?" / B: "No, onestamente ho i miei dubbi."', 'phrase', '059fe2acbf2e66cdcc77f061c61083e621c5373adf52c2aeb012403a22a59287', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_159", "note_culturale": "Esprimere incertezza. ''Avere i miei dubbi'' / ''minulla on epäilykseni'' / ''I have my doubts''."}', NULL),
    (473, '(Dialogo) A: "Oletko varma, että tämä on hyvä idea?" / B: "En, rehellisesti sanottuna minulla on omat epäilykseni."', 'phrase', '6f702e224e63ecba130c1cfb1c0c8b279d08e14675649be9928a0015b9e4b2d8', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_159", "note_culturale": "Esprimere incertezza. ''Avere i miei dubbi'' / ''minulla on epäilykseni'' / ''I have my doubts''."}', NULL),
    (474, '(Dialogo) A: "Are you sure this is a good idea?" / B: "No, honestly I have my doubts."', 'phrase', '8fcd40e60c742b3f05e06d0b69d3d6940e173eae28446b73b18ca6fcd2d89eca', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_159", "note_culturale": "Esprimere incertezza. ''Avere i miei dubbi'' / ''minulla on epäilykseni'' / ''I have my doubts''."}', NULL),
    (475, '(Dialogo) A: "Pensi che vinceremo?" / B: "Non so... non farci troppo affidamento."', 'phrase', 'c96bdd3f8eb49686758743881792cdd844f87a7a6ec669c9cd4d3bf6abf452a9', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_160", "note_culturale": "Invitare alla cautela. ''Non farci affidamento'' (IT), ''älä laske sen varaan'' (FI, non calcolare su quello), ''don''t count on it'' (EN)."}', NULL),
    (476, '(Dialogo) A: "Luuletko, että voitamme?" / B: "En tiedä... älä laske liikaa sen varaan."', 'phrase', 'd6d0319088efa01025f3c8ac66b8da635e79fdf8c0e97623fc60e79488a132d4', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_160", "note_culturale": "Invitare alla cautela. ''Non farci affidamento'' (IT), ''älä laske sen varaan'' (FI, non calcolare su quello), ''don''t count on it'' (EN)."}', NULL),
    (477, '(Dialogo) A: "Do you think we''ll win?" / B: "I don''t know... don''t count on it."', 'phrase', '1b620f86422327b84b04707189394852540a846c2f879e7c7808797500234e42', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_160", "note_culturale": "Invitare alla cautela. ''Non farci affidamento'' (IT), ''älä laske sen varaan'' (FI, non calcolare su quello), ''don''t count on it'' (EN)."}', NULL),
    (478, '(Dialogo) A: "Non sono d''accordo con te." / B: "Ok, ma cerca di capire il mio punto di vista."', 'phrase', 'a936432fae6bde44674b6b3125045af4ed867841d4187c1bd0c769d8c8bd196d', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_161", "note_culturale": "Gestire un disaccordo. ''Capire il punto di vista'' / ''ymmärtää näkökulma'' / ''understand the point of view''."}', NULL),
    (479, '(Dialogo) A: "En ole samaa mieltä kanssasi." / B: "Ok, mutta yritä ymmärtää minun näkökulmani."', 'phrase', 'b8d2e110947e8e9c9397bff09d05927e13beb6c836e730675011fcdf03ccf0ff', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_161", "note_culturale": "Gestire un disaccordo. ''Capire il punto di vista'' / ''ymmärtää näkökulma'' / ''understand the point of view''."}', NULL),
    (480, '(Dialogo) A: "I don''t agree with you." / B: "Okay, but try to understand my point of view."', 'phrase', 'e60d987b86480b5216eb002feeabb8c8ff93ea2876d492908e96267ae1c585ed', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_161", "note_culturale": "Gestire un disaccordo. ''Capire il punto di vista'' / ''ymmärtää näkökulma'' / ''understand the point of view''."}', NULL),
    (481, '(Dialogo) A: "Perché sei così arrabbiato?" / B: "Perché mi ha preso in giro davanti a tutti!"', 'phrase', 'a27fd1b71dfa7d20c3dd75a5e6270c18a91525750357925efbc303cfd1705faf', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_162", "note_culturale": "Idiomi per ''deridere''. ''Prendere in giro'' (IT), ''pilkata'' (FI), ''make fun of'' (EN)."}', NULL),
    (482, '(Dialogo) A: "Miksi olet niin vihainen?" / B: "Koska hän pilkkasi minua kaikkien edessä!"', 'phrase', '60c97e494056bc19c3aad5f760ab8c89204218d81ee4943b07cbeffbff625fa4', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_162", "note_culturale": "Idiomi per ''deridere''. ''Prendere in giro'' (IT), ''pilkata'' (FI), ''make fun of'' (EN)."}', NULL),
    (483, '(Dialogo) A: "Why are you so angry?" / B: "Because he made fun of me in front of everyone!"', 'phrase', 'bd4d19a629ab05e7e533884ede7f8089ac0e586d89f54bd75d41c1cf6e65dc91', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_162", "note_culturale": "Idiomi per ''deridere''. ''Prendere in giro'' (IT), ''pilkata'' (FI), ''make fun of'' (EN)."}', NULL),
    (484, '(Dialogo) A: "Cosa c''è che non va?" / B: "Niente, non sono dell''umore giusto."', 'phrase', 'c9c7bb48ca63b155b0689b4006e3d0d831729153c68eecf6dfbde69e53a252f8', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_163", "note_culturale": "Modo B1 per esprimere irritabilità o tristezza. ''Non essere dell''umore giusto'' / ''ei olla oikealla tuulella'' / ''not in the right mood''."}', NULL),
    (485, '(Dialogo) A: "Mikä on vialla?" / B: "Ei mikään, en ole oikealla tuulella."', 'phrase', '13f18e0c8c54ba38814f233837d3f0b17bd3a7bd8f799f036cd041be441932fe', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_163", "note_culturale": "Modo B1 per esprimere irritabilità o tristezza. ''Non essere dell''umore giusto'' / ''ei olla oikealla tuulella'' / ''not in the right mood''."}', NULL),
    (486, '(Dialogo) A: "What''s wrong?" / B: "Nothing, I''m not in the right mood."', 'phrase', 'ca5d55400ca525714439140ebb9b2a2fe5ebe97c032b43cb84fb5a359c1bd6e7', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_163", "note_culturale": "Modo B1 per esprimere irritabilità o tristezza. ''Non essere dell''umore giusto'' / ''ei olla oikealla tuulella'' / ''not in the right mood''."}', NULL),
    (487, '(Dialogo) A: "Dovresti scusarti con lei." / B: "Neanche per sogno! Ha iniziato lei."', 'phrase', 'af0013dd3d9d41ca36ffdc368a6a86ec9eb4627b8124b2b173c79ec14434e8d4', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_164", "note_culturale": "Rifiuto categorico. ''Neanche per sogno!'' (IT), ''Ei todellakaan!'' (FI, Niente affatto!), ''No way!'' (EN)."}', NULL),
    (488, '(Dialogo) A: "Sinun pitäisi pyytää häneltä anteeksi." / B: "Ei todellakaan! Hän aloitti."', 'phrase', '9c2740c5e68f13f2373ed96e0e7740f89d6e0499e377b3a2bbcf831f1c802ac3', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_164", "note_culturale": "Rifiuto categorico. ''Neanche per sogno!'' (IT), ''Ei todellakaan!'' (FI, Niente affatto!), ''No way!'' (EN)."}', NULL),
    (489, '(Dialogo) A: "You should apologize to her." / B: "No way! She started it."', 'phrase', '831869736f563f2760057cdd7b8ad0d3916ebd66ee2fe22e0953ee5f9d66d067', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_164", "note_culturale": "Rifiuto categorico. ''Neanche per sogno!'' (IT), ''Ei todellakaan!'' (FI, Niente affatto!), ''No way!'' (EN)."}', NULL),
    (490, '(Dialogo) A: "Questa situazione è assurda." / B: "Lo so, non ha né capo né coda."', 'phrase', '182a2c690b14d4f102aa9b8e531f26bca28f22ad2919ce09ae61d799cb343dd1', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_165", "note_culturale": "Idiomi per ''non avere senso''. Tutte e tre le lingue usano la metafora ''né capo né coda'' / ''ei päätä eikä häntää'' / ''neither head nor tail''."}', NULL),
    (491, '(Dialogo) A: "Tämä tilanne on absurdi." / B: "Tiedän, siinä ei ole päätä eikä häntää."', 'phrase', '69d9d1c3c4ec5596fa766f1c1cea467e3cd0a69448f37c7332e6efaf005efb58', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_165", "note_culturale": "Idiomi per ''non avere senso''. Tutte e tre le lingue usano la metafora ''né capo né coda'' / ''ei päätä eikä häntää'' / ''neither head nor tail''."}', NULL),
    (492, '(Dialogo) A: "This situation is absurd." / B: "I know, it has neither head nor tail."', 'phrase', '735c90e9b02d9cbf720adac9582bbc122a05d6b10cd158b960bc5f507245d43f', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_165", "note_culturale": "Idiomi per ''non avere senso''. Tutte e tre le lingue usano la metafora ''né capo né coda'' / ''ei päätä eikä häntää'' / ''neither head nor tail''."}', NULL),
    (493, '(Dialogo) A: "È un film bellissimo, vero?" / B: "Mah, non è il mio genere."', 'phrase', 'f35fc0adae446fb7f991f637d87add2ddce4bcbec404fcce2f585fc40db30150', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_166", "note_culturale": "Idiomi per dire ''non mi piace'' in modo educato. ''Non è il mio genere'' (IT), ''ei ole minun makuuni'' (FI, non è per il mio gusto), ''not my cup of tea'' (EN)."}', NULL),
    (494, '(Dialogo) A: "Onpa hieno elokuva, eikö?" / B: "No, se ei ole minun makuuni."', 'phrase', '7e24290047aee7d47a68dc974a5a60071c49301634db915ee6171b673f1bdd8f', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_166", "note_culturale": "Idiomi per dire ''non mi piace'' in modo educato. ''Non è il mio genere'' (IT), ''ei ole minun makuuni'' (FI, non è per il mio gusto), ''not my cup of tea'' (EN)."}', NULL),
    (495, '(Dialogo) A: "It''s a great movie, isn''t it?" / B: "Meh, it''s not my cup of tea."', 'phrase', '51f86a5b0c058da51cd1a5b3184390d3a03a60caebe11e3fea86f5034b7f8e8e', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_166", "note_culturale": "Idiomi per dire ''non mi piace'' in modo educato. ''Non è il mio genere'' (IT), ''ei ole minun makuuni'' (FI, non è per il mio gusto), ''not my cup of tea'' (EN)."}', NULL),
    (496, '(Dialogo) A: "Mi ha deluso." / B: "Immagino. Ti ha spezzato il cuore."', 'phrase', 'f632b54ffa87c8cafa3ba243f23015bc4ce2df3e1cb73179a7b840765e073065', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_167", "note_culturale": "Metafora comune per il dolore emotivo. ''Spezzare il cuore'' / ''särkeä sydän'' / ''break the heart''."}', NULL),
    (497, '(Dialogo) A: "Petyin häneen." / B: "Ymmärrän. Hän särki sydämesi."', 'phrase', 'e83ef0b05c2ea0365bd3f55375c7ad296d1a7eb0ffbca7fb4f564e53a831bf5f', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_167", "note_culturale": "Metafora comune per il dolore emotivo. ''Spezzare il cuore'' / ''särkeä sydän'' / ''break the heart''."}', NULL),
    (498, '(Dialogo) A: "He/She disappointed me." / B: "I imagine. He/She broke your heart."', 'phrase', '1583f41e7fb6af6fa525b458cbf5ad9fe621dfcae84d3dc1033d2dc59ffbde86', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_167", "note_culturale": "Metafora comune per il dolore emotivo. ''Spezzare il cuore'' / ''särkeä sydän'' / ''break the heart''."}', NULL),
    (499, '(Dialogo) A: "Non so se accettare il lavoro." / B: "Pensaci bene. È una decisione importante."', 'phrase', '631620106fea8c422a75ffba0fab2c454f1fee2d4709b028fa1390bd225d2c4d', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_168", "note_culturale": "Dare il consiglio di riflettere. ''Pensaci bene'' (IT), ''Harkitse tarkkaan'' (FI, Considera attentamente), ''Think it over'' (EN, phrasal verb)."}', NULL),
    (500, '(Dialogo) A: "En tiedä, pitäisikö minun ottaa työ vastaan." / B: "Harkitse tarkkaan. Se on tärkeä päätös."', 'phrase', '6529ff2677c0564040b9ea8fee05a36e69039207376feedca6d2d7d455d10c2f', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_168", "note_culturale": "Dare il consiglio di riflettere. ''Pensaci bene'' (IT), ''Harkitse tarkkaan'' (FI, Considera attentamente), ''Think it over'' (EN, phrasal verb)."}', NULL),
    (501, '(Dialogo) A: "I don''t know if I should accept the job." / B: "Think it over. It''s a big decision."', 'phrase', '86e1553b041bb133dd4ff69ac9e594bef93628c8f161e48d23949ecd6e325aa7', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_168", "note_culturale": "Dare il consiglio di riflettere. ''Pensaci bene'' (IT), ''Harkitse tarkkaan'' (FI, Considera attentamente), ''Think it over'' (EN, phrasal verb)."}', NULL),
    (502, '(Dialogo) A: "Mi ha dato fastidio quello che ha detto." / B: "Lascia perdere. Non ne vale la pena."', 'phrase', '89efd5fb9baf3ee581dd7ed539a9e69c4a5c23402ca163f4316d84798c7864d5', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_169", "note_culturale": "Consiglio di non dare importanza a qualcosa. ''Lascia perdere'' (IT), ''Anna olla'' (FI, Lascia essere), ''Let it go'' (EN)."}', NULL),
    (503, '(Dialogo) A: "Minua ärsytti se, mitä hän sanoi." / B: "Anna olla. Ei se ole sen arvoista."', 'phrase', 'a075c4a8e743e66f3a4a5f7149a2fe367b886dc3cda205d7f5501f0ceacfaf6a', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_169", "note_culturale": "Consiglio di non dare importanza a qualcosa. ''Lascia perdere'' (IT), ''Anna olla'' (FI, Lascia essere), ''Let it go'' (EN)."}', NULL),
    (504, '(Dialogo) A: "It bothered me what he/she said." / B: "Let it go. It''s not worth it."', 'phrase', '9115d40c7e63bee72372badaa592b1628af07b4bee7419f5a101ad4345ef0e6c', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_169", "note_culturale": "Consiglio di non dare importanza a qualcosa. ''Lascia perdere'' (IT), ''Anna olla'' (FI, Lascia essere), ''Let it go'' (EN)."}', NULL),
    (505, '(Dialogo) A: "Cosa ne pensi?" / B: "Per me è una perdita di tempo."', 'phrase', '643e74e36e436eba09f0ca51c9b5f06a0c8412505b799a409a35a2fd899cd79d', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_170", "note_culturale": "Esprimere un''opinione negativa sull''utilità. ''Perdita di tempo'' / ''ajanhukka'' (spreco di tempo) / ''waste of time''."}', NULL),
    (506, '(Dialogo) A: "Mitä mieltä olet?" / B: "Minun mielestäni se on ajanhukkaa."', 'phrase', 'ada147eacbd8c44808f3aaba71c6a1943c427b93eeb9d8987171e223fbf6fc97', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_170", "note_culturale": "Esprimere un''opinione negativa sull''utilità. ''Perdita di tempo'' / ''ajanhukka'' (spreco di tempo) / ''waste of time''."}', NULL),
    (507, '(Dialogo) A: "What do you think about it?" / B: "For me, it''s a waste of time."', 'phrase', '831ea38df61fed06a74e5d31198467fad6493f167d46dc408cd7bf1601e834b0', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_170", "note_culturale": "Esprimere un''opinione negativa sull''utilità. ''Perdita di tempo'' / ''ajanhukka'' (spreco di tempo) / ''waste of time''."}', NULL),
    (508, '(Dialogo) A: "Cosa fai questo weekend?" / B: "Niente di speciale, penso che me ne starò a casa."', 'phrase', '76fde70b69e0d0078276d5b08f07d9b104f0b33f5ea4ad96ece4909e92c79307', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_171", "note_culturale": "Parlare di piani per il tempo libero. ''Starsene a casa'' (IT), ''oleilla kotona'' (FI, starsene a casa), ''stay home'' (EN)."}', NULL),
    (509, '(Dialogo) A: "Mitä teet tänä viikonloppuna?" / B: "Ei mitään erikoista, luulen että oleilen vain kotona."', 'phrase', '6eee2c1d15b467999781cdcde71b77891ab4e75268e5f4cf4c0534591c6741c3', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_171", "note_culturale": "Parlare di piani per il tempo libero. ''Starsene a casa'' (IT), ''oleilla kotona'' (FI, starsene a casa), ''stay home'' (EN)."}', NULL),
    (510, '(Dialogo) A: "What are you doing this weekend?" / B: "Nothing special, I think I''ll just stay home."', 'phrase', 'd0af231c412e5d7f7e59ae33faac9d3d9082d0ba4e00f9f7b522ba9b24841e00', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_171", "note_culturale": "Parlare di piani per il tempo libero. ''Starsene a casa'' (IT), ''oleilla kotona'' (FI, starsene a casa), ''stay home'' (EN)."}', NULL),
    (511, '(Dialogo) A: "Esci spesso la sera?" / B: "No, una volta ogni tanto."', 'phrase', '72bf573aa37150b73d85b117e4e5d219ed19c02df13c8fa6596386e9d2c33103', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_172", "note_culturale": "Esprimere frequenza. ''Una volta ogni tanto'' / ''silloin tällöin'' / ''once in a while''."}', NULL),
    (512, '(Dialogo) A: "Käytkö usein ulkona iltaisin?" / B: "En, silloin tällöin."', 'phrase', '813c71e5a1d1170d96995aa108775464ca04239100ce55a31339691eaf683f08', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_172", "note_culturale": "Esprimere frequenza. ''Una volta ogni tanto'' / ''silloin tällöin'' / ''once in a while''."}', NULL),
    (513, '(Dialogo) A: "Do you go out often in the evening?" / B: "No, once in a while."', 'phrase', '18a665efc11cf7ac82004596dbbefab0b663b46c45260859bb304e88a097ac06', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_172", "note_culturale": "Esprimere frequenza. ''Una volta ogni tanto'' / ''silloin tällöin'' / ''once in a while''."}', NULL),
    (514, '(Dialogo) A: "Andiamo al cinema stasera?" / B: "Perché no? Che film c''è?"', 'phrase', 'bfd9f4e38840b5c5adef77dbee2af4ff75a75fa82b41c29651f5be0401a59154', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_173", "note_culturale": "Modo colloquiale per accettare una proposta (''Perché no?'' / ''Miksi ei?'' / ''Why not?'')."}', NULL),
    (515, '(Dialogo) A: "Mennäänkö leffaan illalla?" / B: "Miksi ei? Mikä elokuva siellä menee?"', 'phrase', '7ff9308aa2eaccafc393fd1bb4758e8032bf44a58c32668b934ecca6289f9fd9', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_173", "note_culturale": "Modo colloquiale per accettare una proposta (''Perché no?'' / ''Miksi ei?'' / ''Why not?'')."}', NULL),
    (516, '(Dialogo) A: "Should we go to the movies tonight?" / B: "Why not? What film is on?"', 'phrase', '7828c5667c9a0d759e0ec6946fba8a6fc8c7edcd132661036340cd11edf8e5c0', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_173", "note_culturale": "Modo colloquiale per accettare una proposta (''Perché no?'' / ''Miksi ei?'' / ''Why not?'')."}', NULL),
    (517, '(Dialogo) A: "Hai visto la partita ieri?" / B: "Sì, è finita in pareggio."', 'phrase', 'c8e8074c8b3c8ec0f7f0410f364ef51028c5a437753b19f04c82da8cd64c9e76', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_174", "note_culturale": "Parlare di risultati sportivi. ''Pareggio'' / ''tasapeli'' / ''draw'' o ''tie''."}', NULL),
    (518, '(Dialogo) A: "Näitkö pelin eilen?" / B: "Joo, se päättyi tasapeliin."', 'phrase', 'c5060102ff4c742e1d51d879c09f191205c072389dd0edb8ed1841ce2eb0708e', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_174", "note_culturale": "Parlare di risultati sportivi. ''Pareggio'' / ''tasapeli'' / ''draw'' o ''tie''."}', NULL),
    (519, '(Dialogo) A: "Did you see the match yesterday?" / B: "Yeah, it ended in a draw (a tie)."', 'phrase', 'bb3ba35810fc4c17c5e570a317dbec3eb92049470c47e977044117ec2f05d341', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_174", "note_culturale": "Parlare di risultati sportivi. ''Pareggio'' / ''tasapeli'' / ''draw'' o ''tie''."}', NULL),
    (520, '(Dialogo) A: "Da quanto tempo suoni la chitarra?" / B: "Da un po'', è il mio passatempo preferito."', 'phrase', '406da6376229fd5f409fe6031af030f6a8b429b39963106c5413c1e0beaca144', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_175", "note_culturale": "Parlare di hobby. ''Passatempo'' / ''lempipuuha'' (attività preferita) / ''hobby''."}', NULL),
    (521, '(Dialogo) A: "Kuinka kauan olet soittanut kitaraa?" / B: "Jo jonkin aikaa, se on lempipuuhaani."', 'phrase', 'e7c8a0696960955a631db38d1355e78c6a748e8fcb9d7a6a820cb31d3b5f8a4a', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_175", "note_culturale": "Parlare di hobby. ''Passatempo'' / ''lempipuuha'' (attività preferita) / ''hobby''."}', NULL),
    (522, '(Dialogo) A: "How long have you played the guitar?" / B: "For a while, it''s my favorite hobby."', 'phrase', 'fb63ae5a5d9e85339dc20620f9fc2dfc3fa9fb7bcfe30d66b5865d5e28ed308d', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_175", "note_culturale": "Parlare di hobby. ''Passatempo'' / ''lempipuuha'' (attività preferita) / ''hobby''."}', NULL),
