    (524, '(Dialogo) A: "Näytät olevan kunnossa!" / B: "Kiitos, yritän päästä takaisin kuntoon."', 'phrase', '51246af09b4ac1e538257b0ca56def767fb3d8091c9d2701c21e34403d816e61', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_176", "note_culturale": "Idiomi per ''tornare in forma fisica''. ''Rimettersi in sesto'' (IT), ''päästä takaisin kuntoon'' (FI), ''get back in shape'' (EN)."}', NULL),
    (525, '(Dialogo) A: "You look fit!" / B: "Thanks, I''m trying to get back in shape."', 'phrase', 'cdc6b49c1f6db3571ac4d56b35add200e3968acdf6d58fd2b10b7d96a6c4736a', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_176", "note_culturale": "Idiomi per ''tornare in forma fisica''. ''Rimettersi in sesto'' (IT), ''päästä takaisin kuntoon'' (FI), ''get back in shape'' (EN)."}', NULL),
    (526, '(Dialogo) A: "Vieni a correre domani?" / B: "Mmm, non so... vedo come mi sento."', 'phrase', 'a86f400f540cf6929c92f6530ad5af5b7e5afaa8ed7c6c29e9b4024f70211f60', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_177", "note_culturale": "Risposta interlocutoria, per non dare una risposta definitiva. ''Vedo come mi sento'' / ''katson, miltä tuntuu'' / ''I''ll see how I feel''."}', NULL),
    (527, '(Dialogo) A: "Tuletko juoksemaan huomenna?" / B: "Mmm, en tiedä... katson, miltä minusta tuntuu."', 'phrase', '484dd810c10b924593fc79e6249c84a6c1f4a97cf45ddebead62f5b3e5aa524d', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_177", "note_culturale": "Risposta interlocutoria, per non dare una risposta definitiva. ''Vedo come mi sento'' / ''katson, miltä tuntuu'' / ''I''ll see how I feel''."}', NULL),
    (528, '(Dialogo) A: "Coming for a run tomorrow?" / B: "Mmm, I don''t know... I''ll see how I feel."', 'phrase', '14d56d5e265e628ec03b6209d0b9c6cd383a09c18e62ce5ad9c0e6411be4beb1', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_177", "note_culturale": "Risposta interlocutoria, per non dare una risposta definitiva. ''Vedo come mi sento'' / ''katson, miltä tuntuu'' / ''I''ll see how I feel''."}', NULL),
    (529, '(Dialogo) A: "Hai smesso di fumare?" / B: "Sì, ho smesso da un mese."', 'phrase', '0556bc12014b5e624c8a24d1caad4bb1d1e888450e31f398b9ef76e82d97d152', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_178", "note_culturale": "Parlare di un''abitudine interrotta. ''Smettere'' / ''lopettaa'' / ''quit''."}', NULL),
    (530, '(Dialogo) A: "Lopetitko tupakoinnin?" / B: "Kyllä, lopetin kuukausi sitten."', 'phrase', 'f56c996aca59239c9d7244e2548d7678984889673458d4b6c0fc4940d79890d4', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_178", "note_culturale": "Parlare di un''abitudine interrotta. ''Smettere'' / ''lopettaa'' / ''quit''."}', NULL),
    (531, '(Dialogo) A: "Did you quit smoking?" / B: "Yes, I quit a month ago."', 'phrase', 'f9e58d5cb8b01d0132ec607781c6b2ee4c52fc830f54488d0de3c1a4d6c90117', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_178", "note_culturale": "Parlare di un''abitudine interrotta. ''Smettere'' / ''lopettaa'' / ''quit''."}', NULL),
    (532, '(Dialogo) A: "Non mangi la torta?" / B: "No, grazie. Sono a dieta."', 'phrase', 'f27ce183561116df0ba512a6f3f6c3f2e097c6811ec2fba411cfbc86c27f6d2b', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_179", "note_culturale": "Motivazione standard per rifiutare cibo. ''Essere a dieta'' / ''olla dieetillä'' / ''be on a diet''."}', NULL),
    (533, '(Dialogo) A: "Etkö syö kakkua?" / B: "Ei kiitos. Olen dieetillä."', 'phrase', 'f41466d27446665f112eeb5c6dee0cd8b78b693cd080247bb715f4237ba3276a', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_179", "note_culturale": "Motivazione standard per rifiutare cibo. ''Essere a dieta'' / ''olla dieetillä'' / ''be on a diet''."}', NULL),
    (534, '(Dialogo) A: "You''re not eating the cake?" / B: "No, thanks. I''m on a diet."', 'phrase', 'dd82ae456314eec161261040e0ecba4436b3b144e20275f3373d5f289a3b0292', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_179", "note_culturale": "Motivazione standard per rifiutare cibo. ''Essere a dieta'' / ''olla dieetillä'' / ''be on a diet''."}', NULL),
    (535, '(Dialogo) A: "Stasera cucino io!" / B: "Ok, allora faccio io i piatti."', 'phrase', '653e00a1445b6ade77f70404bae4030494252986f455b8e47d588e04d1d76d6a', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_180", "note_culturale": "Divisione dei compiti domestici. ''Fare i piatti'' / ''tiskata'' / ''do the dishes''."}', NULL),
    (536, '(Dialogo) A: "Minä laitan ruokaa tänään!" / B: "Ok, sitten minä tiskaan."', 'phrase', '5d0737dae1afa03848e815080168b7fcd769fa066d1dedccf4ec6dbf602f4d18', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_180", "note_culturale": "Divisione dei compiti domestici. ''Fare i piatti'' / ''tiskata'' / ''do the dishes''."}', NULL),
    (537, '(Dialogo) A: "I''m cooking tonight!" / B: "Okay, I''ll do the dishes then."', 'phrase', '3e0591e4caa07849e4cf2a69abb6b304fd881fe90b15334e7acb679b8f9f4c44', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_180", "note_culturale": "Divisione dei compiti domestici. ''Fare i piatti'' / ''tiskata'' / ''do the dishes''."}', NULL),
    (538, '(Dialogo) A: "A che ora vai a dormire di solito?" / B: "Tardi, tiro sempre fino a mezzanotte."', 'phrase', 'a820d9e9a97d1c1f522071af3006978d3ef90d0d894c086b0ed1ae3643e9f694', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_181", "note_culturale": "Parlare delle abitudini di sonno. ''Tirare fino a'' (IT), ''valvoa asti'' (FI, stare sveglio fino a), ''stay up until'' (EN)."}', NULL),
    (539, '(Dialogo) A: "Mihin aikaan yleensä menet nukkumaan?" / B: "Myöhään, valvon aina keskiyöhön asti."', 'phrase', 'b6e60fdf40854c8e2c968336a6a7f7422d33f5340888b3a309c367b3a433cc1d', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_181", "note_culturale": "Parlare delle abitudini di sonno. ''Tirare fino a'' (IT), ''valvoa asti'' (FI, stare sveglio fino a), ''stay up until'' (EN)."}', NULL),
    (540, '(Dialogo) A: "What time do you usually go to sleep?" / B: "Late, I always stay up until midnight."', 'phrase', 'b29224820d11ab234b92c3802bcc5dd3f91ad5475422cecb483e08c9f02148db', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_181", "note_culturale": "Parlare delle abitudini di sonno. ''Tirare fino a'' (IT), ''valvoa asti'' (FI, stare sveglio fino a), ''stay up until'' (EN)."}', NULL),
    (541, '(Dialogo) A: "Scusa il ritardo, c''era un traffico terribile!" / B: "Tranquillo, figurati."', 'phrase', '6f2fa5ce7f708fd10510b45b494842b967f46d8d86de989eae922d098ab5eb2a', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_182", "note_culturale": "Giustificazione per un ritardo e risposta rassicurante. ''Traffico'' (IT), ''ruuhka'' (FI, ingorgo), ''traffic jam'' (EN)."}', NULL),
    (542, '(Dialogo) A: "Anteeksi myöhästyminen, oli kamala ruuhka!" / B: "Ei se mitään, eipä kestä."', 'phrase', 'b1409c5552b4ea3be1098eaff7b5263f3652c95e4d6bf9a037062aaa443585eb', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_182", "note_culturale": "Giustificazione per un ritardo e risposta rassicurante. ''Traffico'' (IT), ''ruuhka'' (FI, ingorgo), ''traffic jam'' (EN)."}', NULL),
    (543, '(Dialogo) A: "Sorry I''m late, there was a terrible traffic jam!" / B: "No worries, don''t mention it."', 'phrase', 'ca1b9266257758aba76f33ba499ee3d002b13a08c570c408fe1f9854437b99a0', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_182", "note_culturale": "Giustificazione per un ritardo e risposta rassicurante. ''Traffico'' (IT), ''ruuhka'' (FI, ingorgo), ''traffic jam'' (EN)."}', NULL),
    (544, '(Dialogo) A: "Cosa facciamo stasera? Hai idee?" / B: "Non so, non mi viene in mente niente."', 'phrase', '6ba9d7a92d9a4a9ce69985a9ec75971e9c8ea26a17b723a24eabe4ed9aaa8382', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_183", "note_culturale": "Idiomi per ''non avere idee''. ''Non venire in mente'' (IT), ''ei tule mieleen'' (FI), ''nothing comes to mind'' (EN)."}', NULL),
    (545, '(Dialogo) A: "Mitä tehdään tänä iltana? Haittaako, jos sinulla on ideoita?" / B: "En tiedä, minulle ei tule mitään mieleen."', 'phrase', '3a2bafeda957bcc843cf3bf2695af76ac63828acc7e9e1525d0839dc777b2357', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_183", "note_culturale": "Idiomi per ''non avere idee''. ''Non venire in mente'' (IT), ''ei tule mieleen'' (FI), ''nothing comes to mind'' (EN)."}', NULL),
    (546, '(Dialogo) A: "What are we doing tonight? Any ideas?" / B: "I don''t know, nothing comes to mind."', 'phrase', '5f1fd98560856b4732b42d255f0ffa70ecb9d5ff67e9f164c0ff195367e91896', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_183", "note_culturale": "Idiomi per ''non avere idee''. ''Non venire in mente'' (IT), ''ei tule mieleen'' (FI), ''nothing comes to mind'' (EN)."}', NULL),
    (547, '(Dialogo) A: "Mi daresti un passaggio in stazione?" / B: "Sì, non c''è problema."', 'phrase', 'fbe9b95727dfb68b49a21c1df120dd54df4df65dddfa9c43d8b35599c87baf3e', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_184", "note_culturale": "Richiesta informale di un passaggio. ''Dare un passaggio'' (IT), ''heittää'' (FI, lanciare/dare un passaggio), ''give a ride'' (EN)."}', NULL),
    (548, '(Dialogo) A: "Voisitko heittää minut asemalle?" / B: "Joo, ei ongelmaa."', 'phrase', '99af17f3b1af9c673cab921b2f5628cf36ff80a15c6fd20ebbcfa18146b42bb5', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_184", "note_culturale": "Richiesta informale di un passaggio. ''Dare un passaggio'' (IT), ''heittää'' (FI, lanciare/dare un passaggio), ''give a ride'' (EN)."}', NULL),
    (549, '(Dialogo) A: "Could you give me a ride to the station?" / B: "Yeah, no problem."', 'phrase', 'b4b86ecea93c07335d95e1c8dd26e6723c4027972da8becec7198746ff3b6a02', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_184", "note_culturale": "Richiesta informale di un passaggio. ''Dare un passaggio'' (IT), ''heittää'' (FI, lanciare/dare un passaggio), ''give a ride'' (EN)."}', NULL),
    (550, '(Dialogo) A: "Ti va di venire alla festa con me?" / B: "Grazie dell''invito, ma devo rifiutare."', 'phrase', '0439c11106a6d90b27370d6e4288d5462aefbb7a4da6ae4e3dda67a82498b793', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_185", "note_culturale": "Modo educato B1 per rifiutare un invito."}', NULL),
    (551, '(Dialogo) A: "Haluatko tulla juhliin kanssani?" / B: "Kiitos kutsusta, mutta minun täytyy kieltäytyä."', 'phrase', '5226b21edaff71c7c16a6659f3b24b52867204d1e2ef9240116cead22f30cba0', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_185", "note_culturale": "Modo educato B1 per rifiutare un invito."}', NULL),
    (552, '(Dialogo) A: "Do you want to come to the party with me?" / B: "Thanks for the invite, but I have to decline."', 'phrase', '9ed5a762980ac1fcf2ffae2b1163e5ecd034f3a227a2ef4057d7a13deb2ec736', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_185", "note_culturale": "Modo educato B1 per rifiutare un invito."}', NULL),
    (553, '(Dialogo) A: "Non so cosa fare. Sono nei guai." / B: "Se fossi in te, parlerei con un avvocato."', 'phrase', 'a6f5b10b11b8c1710da60fbd9628535603f90117c35d872ff076fa0e6f8ead21', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_186", "note_culturale": "Dare un consiglio ipotetico. ''Essere nei guai'' (IT), ''olla pulassa'' (FI, essere nei guai), ''be in trouble'' (EN). ''Se fossi in te'' (periodo ipotetico B1)."}', NULL),
    (554, '(Dialogo) A: "En tiedä mitä tehdä. Olen pulassa." / B: "Jos olisin sinä, puhuisin lakimiehen kanssa."', 'phrase', 'be798e7d73527dbe1f5a963f45c344cd052ee98daf433e29fc022c60e1f25797', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_186", "note_culturale": "Dare un consiglio ipotetico. ''Essere nei guai'' (IT), ''olla pulassa'' (FI, essere nei guai), ''be in trouble'' (EN). ''Se fossi in te'' (periodo ipotetico B1)."}', NULL),
    (555, '(Dialogo) A: "I don''t know what to do. I''m in trouble." / B: "If I were you, I''d talk to a lawyer."', 'phrase', 'f416253d171512886f5e67133e9e2620eece056664bdce8c902c7ab0a73ab905', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_186", "note_culturale": "Dare un consiglio ipotetico. ''Essere nei guai'' (IT), ''olla pulassa'' (FI, essere nei guai), ''be in trouble'' (EN). ''Se fossi in te'' (periodo ipotetico B1)."}', NULL),
    (556, '(Dialogo) A: "Ho fatto una figuraccia!" / B: "Dai, non farne un dramma. Succede."', 'phrase', 'ff24e92ef66b5e7e6da5a5450defb9a84f157b553b59614fbf6b0d17ebf8f5a3', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_187", "note_culturale": "Idiomi per ''fare una brutta figura'' e per ''minimizzare''. ''Fare una figuraccia'' (IT), ''nolata itsensä'' (FI), ''make a fool of oneself'' (EN). ''Non farne un dramma'' (IT), ''älä tee siitä numeroa'' (FI, non farne un numero), ''don''t make a big deal'' (EN)."}', NULL),
    (557, '(Dialogo) A: "Nolasin itseni täysin!" / B: "Älä viitsi, älä tee siitä numeroa. Sellaista sattuu."', 'phrase', 'eea323dfa6c01b3ba846fbbc22ba8c29d9b66efc69e1d0d0a96439b9d9ab6cb7', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_187", "note_culturale": "Idiomi per ''fare una brutta figura'' e per ''minimizzare''. ''Fare una figuraccia'' (IT), ''nolata itsensä'' (FI), ''make a fool of oneself'' (EN). ''Non farne un dramma'' (IT), ''älä tee siitä numeroa'' (FI, non farne un numero), ''don''t make a big deal'' (EN)."}', NULL),
    (558, '(Dialogo) A: "I made a fool of myself!" / B: "Come on, don''t make a big deal out of it. It happens."', 'phrase', 'e879657eae3bcb624fa6113f3689f4239cd166539235c7c5f157f76cd1ea4ec5', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_187", "note_culturale": "Idiomi per ''fare una brutta figura'' e per ''minimizzare''. ''Fare una figuraccia'' (IT), ''nolata itsensä'' (FI), ''make a fool of oneself'' (EN). ''Non farne un dramma'' (IT), ''älä tee siitä numeroa'' (FI, non farne un numero), ''don''t make a big deal'' (EN)."}', NULL),
    (559, '(Dialogo) A: "Devo parlarti un attimo." / B: "Ok, dimmi pure."', 'phrase', 'f7b83ddcc86b65dda9672a682579838e6e9f633777246d909828fb56b3d519aa', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_188", "note_culturale": "Introdurre una conversazione seria. La risposta ''dimmi pure'' (IT), ''anna tulla'' (FI, lascia venire), ''go ahead'' (EN) invita a parlare."}', NULL),
    (560, '(Dialogo) A: "Minun täytyy puhua sinulle hetki." / B: "Ok, anna tulla."', 'phrase', '84ded72ebcb94b8e7100891bca99d222c694db35c7fcf2a5dce5cbc2e9d87c99', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_188", "note_culturale": "Introdurre una conversazione seria. La risposta ''dimmi pure'' (IT), ''anna tulla'' (FI, lascia venire), ''go ahead'' (EN) invita a parlare."}', NULL),
    (561, '(Dialogo) A: "I need to talk to you for a moment." / B: "Okay, go ahead."', 'phrase', '9f80b8d2ff8b569432f0c59d5ad4b99aa6b552cecef89eed7440a4dc6a52eef1', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_188", "note_culturale": "Introdurre una conversazione seria. La risposta ''dimmi pure'' (IT), ''anna tulla'' (FI, lascia venire), ''go ahead'' (EN) invita a parlare."}', NULL),
    (562, '(Dialogo) A: "Possiamo rimandare la riunione?" / B: "Certo, facciamo domani alla stessa ora?"', 'phrase', '6038af0706af598f9b305f6e4bf35d2606d81b87e058803945959835661656a4', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_189", "note_culturale": "Chiedere di riprogrammare. ''Rimandare'' / ''siirtää'' (spostare) / ''postpone''. La risposta è una controproposta."}', NULL),
    (563, '(Dialogo) A: "Voimmeko siirtää kokousta?" / B: "Toki, sopisko huomenna samaan aikaan?"', 'phrase', '1daedd8a75e15363ded16ad66ba5fcc8e7259ae9df5c3b0def28f0e55d6b16fd', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_189", "note_culturale": "Chiedere di riprogrammare. ''Rimandare'' / ''siirtää'' (spostare) / ''postpone''. La risposta è una controproposta."}', NULL),
    (564, '(Dialogo) A: "Can we postpone the meeting?" / B: "Sure, how about tomorrow at the same time?"', 'phrase', '1542973a0da868c587723c1a9bfabc2be61a1f6f49b4c50ff1ab4d36509896d9', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_189", "note_culturale": "Chiedere di riprogrammare. ''Rimandare'' / ''siirtää'' (spostare) / ''postpone''. La risposta è una controproposta."}', NULL),
    (565, '(Dialogo) A: "Mi sono offeso per quello che ha detto." / B: "Lo so, ma non l''ha fatto apposta."', 'phrase', '88ceaafb92f907b3e385520eadad6e9ee0131d8b6b9955bfc2d1d9b5a45ca946', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_190", "note_culturale": "Spiegare l''intenzionalità. ''Apposta'' / ''tahallaan'' / ''on purpose''."}', NULL),
    (566, '(Dialogo) A: "Loukkaannuin siitä, mitä hän sanoi." / B: "Tiedän, mutta hän ei tehnyt sitä tahallaan."', 'phrase', 'c51b905d2dad88537609c52c5e3103e3794a53d4fed42a0f1ecfb6eff3bffdfd', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_190", "note_culturale": "Spiegare l''intenzionalità. ''Apposta'' / ''tahallaan'' / ''on purpose''."}', NULL),
    (567, '(Dialogo) A: "I was offended by what he said." / B: "I know, but he didn''t do it on purpose."', 'phrase', 'b15a4e84dd6fc0e20f0b90edb80100d0c52537e98cf805c24c13aa403a4679fe', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_190", "note_culturale": "Spiegare l''intenzionalità. ''Apposta'' / ''tahallaan'' / ''on purpose''."}', NULL),
    (568, '(Dialogo) A: "Hai deciso cosa fare?" / B: "No, sono ancora indeciso."', 'phrase', '0b435a64592a4fa31e1192fba28356ea342e7038a6fb6a2ba121345e29d35236', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_191", "note_culturale": "Idiomi per ''essere indeciso''. ''Essere indeciso'' (IT), ''olla kahden vaiheilla'' (FI, essere tra due fasi), ''be on the fence'' (EN, essere sulla staccionata)."}', NULL),
    (569, '(Dialogo) A: "Oletko päättänyt mitä teet?" / B: "En, olen yhä kahden vaiheilla."', 'phrase', '84b249319b50a9167d86425b01ca8c5c0034d4f8a20bcfc7814f5f6d727ee9de', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_191", "note_culturale": "Idiomi per ''essere indeciso''. ''Essere indeciso'' (IT), ''olla kahden vaiheilla'' (FI, essere tra due fasi), ''be on the fence'' (EN, essere sulla staccionata)."}', NULL),
    (570, '(Dialogo) A: "Have you decided what to do?" / B: "No, I''m still on the fence."', 'phrase', '4c769a31ceedb27efdbd74bf149e36aa2ca72263df75821a1cb61dbf6f8e317a', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_191", "note_culturale": "Idiomi per ''essere indeciso''. ''Essere indeciso'' (IT), ''olla kahden vaiheilla'' (FI, essere tra due fasi), ''be on the fence'' (EN, essere sulla staccionata)."}', NULL),
    (571, '(Dialogo) A: "Non dovevi dirlo." / B: "Hai ragione, ho sbagliato."', 'phrase', 'bc429ae942f4ec3fcbb7b3ec5687a1d57f84882173c6b06d0ef540b1ec56d712', 'B1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_192", "note_culturale": "Ammettere un errore. ''Ho sbagliato'' (IT), ''tein virheen'' (FI, ho fatto un errore), ''I messed up'' (EN, colloquiale B1)."}', NULL),
    (572, '(Dialogo) A: "Sinun ei olisi pitänyt sanoa sitä." / B: "Olet oikeassa, tein virheen."', 'phrase', 'f9ca83417dd35d69211b315649ed00c240dd10b6341988d890f2a46c81fbd471', 'B1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_192", "note_culturale": "Ammettere un errore. ''Ho sbagliato'' (IT), ''tein virheen'' (FI, ho fatto un errore), ''I messed up'' (EN, colloquiale B1)."}', NULL),
    (573, '(Dialogo) A: "You shouldn''t have said that." / B: "You''re right, I messed up."', 'phrase', '3255695f97b38ae854fb3ad7e564f23d47f420765f52b2a8e00218f6d1bfdf3e', 'B1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_192", "note_culturale": "Ammettere un errore. ''Ho sbagliato'' (IT), ''tein virheen'' (FI, ho fatto un errore), ''I messed up'' (EN, colloquiale B1)."}', NULL),
